---
/**
 * Accordion.astro -- astro-shad accordion root. Converted from shadcn
 * ui/accordion.tsx (Radix Accordion): this wrapper owns the behaviour
 * (vanilla JS, event delegation); items are <AccordionItem> children.
 *
 * type="single" (default) closes the other items when one opens;
 * type="multiple" lets any number stay open. `multipleOpen` is a boolean
 * alias for type="multiple" (multipleOpen wins when both are passed).
 *
 *   <Accordion>
 *     <AccordionItem title="Is it accessible?">Yes -- ARIA wired.</AccordionItem>
 *     <AccordionItem title="Is it styled?" open>Neutral tokens only.</AccordionItem>
 *   </Accordion>
 */
import { cn } from "../../lib/utils";

interface Props {
  type?: "single" | "multiple";
  /** boolean alias for type="multiple" */
  multipleOpen?: boolean;
  class?: string;
  [key: string]: unknown;
}

const { type = "single", multipleOpen = false, class: className, ...rest } = Astro.props;
const mode = multipleOpen ? "multiple" : type;
---

<div class={cn("divide-y divide-border border-y border-border", className)} data-astro-shad-accordion={mode} {...rest}>
  <slot />
</div>

<script>
  function setOpen(trigger: Element, open: boolean) {
    trigger.setAttribute("aria-expanded", String(open));
    const panel = trigger.closest("[data-accordion-item]")?.querySelector<HTMLElement>("[data-accordion-panel]");
    if (panel) panel.dataset.state = open ? "open" : "closed";
  }

  document.querySelectorAll<HTMLElement>("[data-astro-shad-accordion]").forEach((root) => {
    root.addEventListener("click", (e) => {
      const trigger = (e.target as HTMLElement).closest("[data-accordion-trigger]");
      if (!trigger || trigger.closest("[data-astro-shad-accordion]") !== root) return;
      const isOpen = trigger.getAttribute("aria-expanded") === "true";
      if (root.dataset.astroShadAccordion === "single" && !isOpen) {
        root.querySelectorAll('[data-accordion-trigger][aria-expanded="true"]').forEach((other) => setOpen(other, false));
      }
      setOpen(trigger, !isOpen);
    });
  });
</script>

---
/**
 * AccordionItem.astro -- one collapsible row inside <Accordion>. Trigger
 * markup + panel; behaviour lives in the Accordion root's script.
 *
 * Height animation is the CSS grid-rows trick (0fr -> 1fr), so panels can
 * hold arbitrary content with no measured heights and no JS animation.
 * Chevron is an inlined lucide chevron-down (self-contained on purpose --
 * primitives carry no icon dependency; icon *props* on richer components
 * use astro-icon).
 */
import { cn } from "../../lib/utils";

interface Props {
  title: string;
  /** Render this item expanded on load. */
  open?: boolean;
  class?: string;
  [key: string]: unknown;
  /** Highlights the text and border with the theme's primary accent color when open */
  highlight?: boolean;
}

const { title, open = false, class: className, highlight = false, ...rest } = Astro.props;
---

<div
  class={cn(
    !highlight && "has-[[aria-expanded=true]]:border-ring/40",
    // Accent open state border
    highlight && "has-[[aria-expanded=true]]:border-primary",
    className,
  )}
  data-accordion-item
  {...rest}
>
  <h3>
    <button
      type="button"
      data-accordion-trigger
      aria-expanded={open ? "true" : "false"}
      class={cn(
        "group flex w-full cursor-pointer items-center justify-between gap-4 py-4 text-left text-sm font-medium text-foreground transition-colors hover:font-bold focus-visible:ring-2 focus-visible:ring-ring focus-visible:outline-none",
        // Accent open state text and icons
        highlight && "aria-expanded:text-accent [&_svg]:group-aria-expanded:text-accent",
      )}
    >
      {title}
      <svg
        xmlns="http://www.w3.org/2000/svg"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        stroke-width="2"
        stroke-linecap="round"
        stroke-linejoin="round"
        aria-hidden="true"
        class="size-4 shrink-0 text-muted-foreground transition-transform duration-200 group-aria-expanded:rotate-180"
      >
        <path d="m6 9 6 6 6-6"></path>
      </svg>
    </button>
  </h3>
  <div
    data-accordion-panel
    data-state={open ? "open" : "closed"}
    class="grid grid-rows-[0fr] transition-[grid-template-rows] duration-200 data-[state=open]:grid-rows-[1fr]"
  >
    <div class="overflow-hidden">
      <div class="pb-4 text-sm text-muted-foreground">
        <slot />
      </div>
    </div>
  </div>
</div>
